import React from 'react';
import NavBar from './NavBar';


const Mainpage = () => {
  return (
    <>
      <NavBar/> 
      <h1>Information Technology Manager with more than 7 years of experience in the IT Field delivering
technical advisory and support to the reputed hotel chain ‘IHG Hotels & Resorts’. Proven success in
managing high-end network devices, servers, and workstations. Innovative professional with strong
passion and expertise in Information Technology.<span/>Part-time Python and React developer passionate about crafting innovative solutions.</h1>     
    </>
  )
}

export default Mainpage
